)

// digitSum calculates the sum of the digits of a non-negative integer n.
func digitSum(n int) int {
	sum := 0
	for n > 0 {
		sum += n % 10
		n /= 10
	}
	return sum
}

// solve finds the number of different valid arrays.
func solve(digitSumArr []int64) int64 {
	MOD := int64(1e9 + 7)
	N := len(digitSumArr)

	// 1. Precalculation: Find all valid numbers <= 5000 for each digit sum S.
	// L[S] stores a sorted list of integers x <= 5000 such that digitSum(x) = S.
	L := make(map[int][]int)
	for x := 0; x <= 5000; x++ {
		s := digitSum(x)
		L[s] = append(L[s], x)
	}

	// dp_prev[j]: count of valid prefixes ending with the number L_prev[j]
	var dp_prev []int64

	// --- Base Case: i = 0 ---
	S0 := int(digitSumArr[0])
	L0, exists := L[S0]
	if !exists {
		return 0
	}

	// For the first element, every valid number contributes 1 count.
	dp_prev = make([]int64, len(L0))
	for j := range L0 {
		dp_prev[j] = 1
	}

	// --- DP Transitions: i = 1 to N-1 ---
	for i := 1; i < N; i++ {
		Si := int(digitSumArr[i])
		Si_1 := int(digitSumArr[i-1])

		L_curr, exists_curr := L[Si]
		if !exists_curr {
			return 0
		}

		L_prev, exists_prev := L[Si_1]
		if !exists_prev {
			// Should not happen if i-1 >= 0, but safety check
			return 0
		}

		// 1. Calculate Prefix Sums for dp_prev
		P_prev := make([]int64, len(dp_prev))
		sum := int64(0)
		for k := range dp_prev {
			sum = (sum + dp_prev[k]) % MOD
			P_prev[k] = sum
		}

		// 2. Calculate dp_curr
		dp_curr := make([]int64, len(L_curr))

		for j, x_curr := range L_curr {
			// We need to sum dp_prev[k] for all k such that L_prev[k] <= x_curr.

			// Use binary search: find the index of the first element in L_prev strictly greater than x_curr.
			// sort.Search returns the smallest index k such that f(k) is true.
			// Here f(k) is L_prev[k] > x_curr.
			k_idx := sort.Search(len(L_prev), func(k int) bool {
				return L_prev[k] > x_curr
			})

			// k_idx is the count of elements <= x_curr. The highest index is k_idx - 1.
			k_max := k_idx - 1

			count := int64(0)
			if k_max >= 0 {
				// The sum is P_prev[k_max]
				count = P_prev[k_max]
			}
			dp_curr[j] = count
		}

		dp_prev = dp_curr
	}

	// Final result: Sum of all counts in the last DP layer
	totalCount := int64(0)
	for _, count := range dp_prev {
		totalCount = (totalCount + count) % MOD
	}

	return totalCount
}
