			k_idx := sort.Search(len(L_prev), func(k int) bool {
				return L_prev[k] > x_curr
			})

			// k_idx is the count of elements <= x_curr. The highest index is k_idx - 1.
			k_max := k_idx - 1

			count := int64(0)
			if k_max >= 0 {
				// The sum is P_prev[k_max]
				count = P_prev[k_max]
			}
			dp_curr[j] = count
		}

		dp_prev = dp_curr
	}

	// Final result: Sum of all counts in the last DP layer
	totalCount := int64(0)
	for _, count := range dp_prev {
		totalCount = (totalCount + count) % MOD
	}

	return totalCount
}
